import "math"

func solve(nums []int64, k int64) int64 {
	n := len(nums)

	// Precompute prefix maximums: prefixMax[i] = max(nums[0...i])
	prefixMax := make([]int64, n)
	currentMax := int64(math.MinInt64)
	for i := 0; i < n; i++ {
		if nums[i] > currentMax {
			currentMax = nums[i]
		}
		prefixMax[i] = currentMax
	}

	// Precompute suffix minimums: suffixMin[i] = min(nums[i...n-1])
	suffixMin := make([]int64, n)
	currentMin := int64(math.MaxInt64)
	for i := n - 1; i >= 0; i-- {
		if nums[i] < currentMin {
			currentMin = nums[i]
		}
		suffixMin[i] = currentMin
	}

	// Iterate through each index i to check the instability value
	for i := 0; i < n; i++ {
		// Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
		unstableValue := prefixMax[i] - suffixMin[i]

		// Check if the index is stable
		if unstableValue <= k {
			// Found the smallest stable index
			return int64(i)
		}
	}

	// If no stable index is found
	return -1
}
